    from onnx9000.converters.torch_like import int
    from onnx9000.converters.frontend.tensor import Tensor
    from onnx9000.core.dtypes import DType

    inp = Tensor(name="test", shape=(1,), dtype=DType.FLOAT32)
    try:
        res = int([inp, inp], 0)
    except Exception:
        try:
            res = int([inp, inp])
        except Exception:
            try:
                res = int(inp, inp, inp)
            except Exception:
                try:
                    res = int(inp, inp)
                except Exception:
                    try:
                        res = int(inp)
                    except Exception:
                        res = None


